  /** Coverage level of the job. */
  readonly coverage: Maybe<Scalars['Float']['output']>;
  /** When the job was created. */
  readonly createdAt: Scalars['Time']['output'];
  /** Whether the job was created by a tag. */
  readonly createdByTag: Scalars['Boolean']['output'];
  /** Detailed status of the job. */
  readonly detailedStatus: Maybe<DetailedStatus>;
  /** Downstream pipeline for a bridge. */
  readonly downstreamPipeline: Maybe<Pipeline>;
  /** Duration of the job in seconds. */
  readonly duration: Maybe<Scalars['Int']['output']>;
  /** When the job was erased. */
  readonly erasedAt: Maybe<Scalars['Time']['output']>;
  /** Exit code of the job. Available for jobs that started after upgrading to GitLab 16.10 and failed with an exit code. */
  readonly exitCode: Maybe<Scalars['Int']['output']>;
  /** Message on why the job failed. */
  readonly failureMessage: Maybe<Scalars['String']['output']>;
  /** When a job has finished running. */
  readonly finishedAt: Maybe<Scalars['Time']['output']>;
  /** ID of the job. */
  readonly id: Maybe<Scalars['JobID']['output']>;
  /** Input values that were used when the job was created or retried. A value is only present in the field if it differs from the default value in the input configuration. This field can only be resolved for one job in any single request. */
  readonly inputs: Maybe<ReadonlyArray<CiInputsField>>;
  /** Input specification for the job. Defines the inputs that can be provided when creating or retrying the job. This field can only be resolved for one job in any single request. */
  readonly inputsSpec: Maybe<ReadonlyArray<CiInputsSpec>>;
  /** Indicates the type of job. */
  readonly kind: CiJobKind;
  /** Whether the job has a manual action. */
  readonly manualJob: Maybe<Scalars['Boolean']['output']>;
  /** Variables added to a manual job when the job is triggered. */
  readonly manualVariables: Maybe<CiManualVariableConnection>;
  /** Name of the job. */
  readonly name: Maybe<Scalars['String']['output']>;
  /** References to builds that must complete before the jobs run. */
  readonly needs: Maybe<CiBuildNeedConnection>;
  /** Pipeline the job belongs to. */
  readonly pipeline: Maybe<PipelineInterface>;
  /** Play path of the job. */
  readonly playPath: Maybe<Scalars['String']['output']>;
  /** Indicates the job can be played. */
  readonly playable: Scalars['Boolean']['output'];
  /** Jobs from the previous stage. */
  readonly previousStageJobs: Maybe<CiJobConnection>;
  /**
   * Jobs that must complete before the job runs. Returns `BuildNeed`, which is the needed jobs if the job uses the `needs` keyword, or the previous stage jobs otherwise. Deprecated in GitLab 16.4: Replaced by previousStageJobs and needs fields.
   * @deprecated Replaced by previousStageJobs and needs fields. Deprecated in GitLab 16.4.
   */
  readonly previousStageJobsOrNeeds: Maybe<JobNeedUnionConnection>;
  /** Project that the job belongs to. */
  readonly project: Maybe<Project>;
  /** When the job was enqueued and marked as pending. */
  readonly queuedAt: Maybe<Scalars['Time']['output']>;
  /** How long the job was enqueued before starting. */
  readonly queuedDuration: Maybe<Scalars['Duration']['output']>;
  /** Ref name of the job. */
  readonly refName: Maybe<Scalars['String']['output']>;
  /** Path to the ref. */
  readonly refPath: Maybe<Scalars['String']['output']>;
  /** Indicates that the job has been retried. */
  readonly retried: Maybe<Scalars['Boolean']['output']>;
  /** Retry path of the job. */
  readonly retryPath: Maybe<Scalars['String']['output']>;
  /** Indicates the job can be retried. */
  readonly retryable: Scalars['Boolean']['output'];
  /** Runner assigned to execute the job. */
  readonly runner: Maybe<CiRunner>;
  /** Runner manager assigned to the job. */
  readonly runnerManager: Maybe<CiRunnerManager>;
  /** Indicates the job is scheduled. */
  readonly scheduled: Scalars['Boolean']['output'];
  /** Schedule for the build. */
  readonly scheduledAt: Maybe<Scalars['Time']['output']>;
  /** Type of job scheduling. Value is `dag` if the job uses the `needs` keyword, and `stage` otherwise. */
  readonly schedulingType: Maybe<Scalars['String']['output']>;
  /** Short SHA1 ID of the commit. */
  readonly shortSha: Scalars['String']['output'];
  /** Policy or action that initiated the job. If not set, the value is inherited from the pipeline. */
  readonly source: Maybe<Scalars['String']['output']>;
  /** Stage of the job. */
  readonly stage: Maybe<CiStage>;
  /** When the job was started. */
  readonly startedAt: Maybe<Scalars['Time']['output']>;
  /** Status of the job. */
  readonly status: Maybe<CiJobStatus>;
  /** Indicates the job is stuck. */
  readonly stuck: Scalars['Boolean']['output'];
  /** Tags for the current job. */
  readonly tags: Maybe<ReadonlyArray<Scalars['String']['output']>>;
  /** Trace generated by the job. */
  readonly trace: Maybe<CiJobTrace>;
  /** Whether the job was triggered. */
  readonly triggered: Maybe<Scalars['Boolean']['output']>;
  /** Permissions for the current user on the resource */
